Code.Terraform:
```hcl
# Terraform：最小 EBS スナップショットライフサイクルポリシー
resource "aws_dlm_lifecycle_policy" "<example_resource_name>" {
  description        = "<description>"
  execution_role_arn = "<example_resource_arn>"
  state              = "ENABLED" # 重要：ポリシーを有効にしてチェックでカウントされるようにする

  policy_details {
    policy_type    = "EBS_SNAPSHOT_MANAGEMENT" # 重要：EBS スナップショットライフサイクルポリシーを作成
    resource_types = ["VOLUME"]
    target_tags = {
      "<tag_key>" = "<tag_value>" # 重要：タグでターゲットボリュームを選択
    }
    schedule {
      create_rule {
        interval      = 24
        interval_unit = "HOURS"
      }
      retain_rule {
        count = 1
      }
    }
  }
}
```
